<template>
    <div class="demo-wrapper">
        <div class="demo-menu">
            <div class="menu-title">样例</div>
            <div class="menu-list" @click="selectDemo(item)" v-for="(item,index) in menuList" :key="index" :class="{active:item.url==curPageUrl}">
                {{item.name}}
            </div>
        </div>
        <div class="demo-body">
            <router-view></router-view>
        </div>
    </div>
</template>

<script>
import { ref, onMounted, onUpdated } from "vue";
import "highlight.js/styles/dracula.css";
import { useRouter } from "vue-router";
export default {
    setup() {
        const menuList = ref([
            { name: "mapbox添加点线面", url: "/demo/mapboxdemo1" },
            { name: "mapbox添加3d模型", url: "/demo/mapboxdemo2" }
        ]);
        const curPageUrl = ref(null);
        const router = useRouter();

        // 选择样例
        const selectDemo = (data) => {
            router.push({ path: data.url });
        };

        onMounted(() => {
            curPageUrl.value = router.currentRoute.value.path;
        });

        onUpdated(() => {
            curPageUrl.value = router.currentRoute.value.path;
        });
        return {
            menuList,
            curPageUrl,
            selectDemo
        };
    }
};
</script>

<style lang="scss">
.demo-wrapper {
    width: 100%;
    height: 100%;
    display: flex;

    .demo-menu {
        width: 300px;
        height: 100%;
        border-right: 1px solid #eaecef;
        overflow: auto;
        display: flex;
        flex-direction: column;

        .menu-title {
            height: 45px;
            display: flex;
            align-items: center;
            padding: 0 16px;
        }

        .menu-list {
            padding: 0 32px;
            height: 36px;
            display: flex;
            align-items: center;
            cursor: pointer;

            &:hover {
                color: #3489fd;
            }

            &.active {
                font-weight: 600;
                color: #3489fd;
                border-right: 3px solid #3489fd;
                background: rgba(52, 137, 253, 0.2);
            }
        }
    }

    .demo-body {
        height: 100%;
        flex: 1;
    }
}
</style>
